// Extract data from Odoo webhook
const body = $input.first().json.body;

const query = body.query;
const today = body.today;
const models = body.models;

// Build a concise schema description for Claude
let schemaText = '';
for (const [modelName, info] of Object.entries(models)) {
  schemaText += `\n## ${modelName} (${info.name})\n`;
  schemaText += 'Fields: ';
  const fieldEntries = Object.entries(info.fields)
    .map(([fname, f]) => {
      let desc = `${fname} (${f.type}, "${f.label}")`;
      if (f.options) desc += ` [options: ${f.options.map(o => o[0]).join(', ')}]`;
      if (f.relation) desc += ` → ${f.relation}`;
      return desc;
    });
  schemaText += fieldEntries.join(', ') + '\n';
}

return [{
  json: {
    query,
    today,
    schemaText
  }
}];

// Parse Claude's response
const response = $input.first().json;

try {
  // Extract text from Claude's response
  let text = '';
  if (response.content && Array.isArray(response.content)) {
    text = response.content
      .filter(block => block.type === 'text')
      .map(block => block.text)
      .join('');
  }

  // Clean up: remove markdown code fences if present
  text = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  // Parse the JSON
  const result = JSON.parse(text);

  // Validate required fields
  const required = ['model', 'domain', 'groupby', 'measures'];
  for (const field of required) {
    if (!(field in result)) {
      throw new Error(`Missing required field: ${field}`);
    }
  }

  return [{ json: result }];

} catch (err) {
  // Return error details for debugging
  return [{
    json: {
      error: `Failed to parse AI response: ${err.message}`,
      raw_response: response.content?.[0]?.text?.substring(0, 500) || 'No response'
    }
  }];
}
